def load_assessment_from_db(created_by: str = None) -> pd.DataFrame:
    """Load assessments. If created_by given, filter to that user; else return all."""
    with get_db() as conn:
        if created_by:
            rows = conn.execute(
                "SELECT id, date_added, tenant_name, area_name, category, sqft, "
                "created_by, assessment_name FROM assessment_data "
                "WHERE created_by = ? ORDER BY id", (created_by,)
            ).fetchall()
        else:
            rows = conn.execute(
                "SELECT id, date_added, tenant_name, area_name, category, sqft, "
                "created_by, assessment_name FROM assessment_data ORDER BY id"
            ).fetchall()
    if rows:
        return pd.DataFrame([dict(r) for r in rows])
    return pd.DataFrame(columns=["id","date_added","tenant_name","area_name",
                                  "category","sqft","created_by","assessment_name"])


def save_assessment_row_to_db(date_added, tenant_name, area_name, category,
                               sqft, created_by="", assessment_name=""):
    with get_db() as conn:
        conn.execute(
            "INSERT INTO assessment_data "
            "(date_added, tenant_name, area_name, category, sqft, created_by, assessment_name) "
            "VALUES (?,?,?,?,?,?,?)",
            (date_added, tenant_name, area_name, category, sqft, created_by, assessment_name)
        )
        conn.commit()
    # Return the new row's id
    with get_db() as conn:
        row = conn.execute("SELECT last_insert_rowid()").fetchone()
        return row[0] if row else None


def update_assessment_row_in_db(row_id: int, area_name: str, category: str,
                                 sqft: float, assessment_name: str):
    with get_db() as conn:
        conn.execute(
            "UPDATE assessment_data SET area_name=?, category=?, sqft=?, assessment_name=? "
            "WHERE id=?",
            (area_name, category, sqft, assessment_name, row_id)
        )
        conn.commit()


def delete_assessment_row_in_db(row_id: int):
    with get_db() as conn:
        conn.execute("DELETE FROM assessment_data WHERE id=?", (row_id,))
        conn.commit()


def delete_assessment_rows_for_tenants(tenant_names: list):
    placeholders = ",".join("?" * len(tenant_names))
    with get_db() as conn:
        conn.execute(f"DELETE FROM assessment_data WHERE tenant_name IN ({placeholders})",
                     tenant_names)
        conn.commit()


def delete_all_assessment_data():
    with get_db() as conn:
        conn.execute("DELETE FROM assessment_data")
        conn.commit()


def save_full_assessment_to_db(df: pd.DataFrame):
    """Overwrite all assessment data in DB from a DataFrame (legacy compat)."""
    with get_db() as conn:
        conn.execute("DELETE FROM assessment_data")
        for _, row in df.iterrows():
            conn.execute(
                "INSERT INTO assessment_data "
                "(date_added, tenant_name, area_name, category, sqft, created_by, assessment_name) "
                "VALUES (?,?,?,?,?,?,?)",
                (str(row.get("Date Added", "")), str(row.get("Tenant Name", "")),
                 str(row.get("Name of Area", "")), str(row.get("Category", "")),
                 float(row.get("Coverage (SQFT)", 0)),
                 str(row.get("Created By", "")), str(row.get("Assessment Name", "")))
            )
        conn.commit()


def db_to_display_df(db_df: pd.DataFrame) -> pd.DataFrame:
    if db_df.empty:
        return pd.DataFrame(columns=["ID","Assessment Name","Date Added","Tenant Name",
                                      "Name of Area","Category","Coverage (SQFT)","Created By"])
    return db_df.rename(columns={
        "id":              "ID",
        "assessment_name": "Assessment Name",
        "date_added":      "Date Added",
        "tenant_name":     "Tenant Name",
        "area_name":       "Name of Area",
        "category":        "Category",
        "sqft":            "Coverage (SQFT)",
        "created_by":      "Created By",
    })


def _get_seed_users() -> dict:
    """Read initial users from st.secrets, falling back to defaults."""
    DOMAIN = "@dexxora360"
    try:
        raw = st.secrets.get("users", {})
        if raw:
            result = {}
            for uname, udata in raw.items():
                # Ensure domain suffix on every username
                key = uname if uname.endswith(DOMAIN) else uname + DOMAIN
                result[key] = {
                    "password_hash": udata["password_hash"],
                    "role":          udata["role"],
                    "tenant_access": list(udata["tenant_access"]),
                    "display_name":  udata["display_name"],
                }
            return result
    except Exception:
        pass
    # Hard-coded fallback
    return {
        "admin@dexxora360": {
            "password_hash": hash_pw("dex123"),
            "role":          "admin",
            "tenant_access": ["EDEN Tenant", "Thaala Tenant"],
            "display_name":  "Administrator",
        },
        "eden_user@dexxora360": {
            "password_hash": hash_pw("Eden@123"),
            "role":          "user",
            "tenant_access": ["EDEN Tenant"],
            "display_name":  "EDEN Staff",
        },
        "thaala_user@dexxora360": {
            "password_hash": hash_pw("Thaala@123"),
            "role":          "user",
            "tenant_access": ["Thaala Tenant"],
            "display_name":  "Thaala Staff",
        },
    }


def load_users_from_db() -> dict:
    """Load all users from the /tmp SQLite database into a plain dict."""
    with get_db() as conn:
        rows = conn.execute("SELECT * FROM users").fetchall()
        cols = [r[1] for r in conn.execute("PRAGMA table_info(users)").fetchall()]
    access_col = "tenant_access" if "tenant_access" in cols else "hotel_access"
    return {
        row["username"]: {
            "display_name":  row["display_name"],
            "role":          row["role"],
            "tenant_access": json.loads(row[access_col]),
            "password_hash": row["password_hash"],
        }
        for row in rows
    }


def save_user_to_db(username: str, ud: dict):
    """Insert or replace a single user record."""
    with get_db() as conn:
        conn.execute(
            "INSERT OR REPLACE INTO users VALUES (?,?,?,?,?)",
            (username, ud["display_name"], ud["role"],
             json.dumps(ud["tenant_access"]), ud["password_hash"])
        )
        conn.commit()


def delete_user_from_db(username: str):
    """Delete a user from the database."""
    with get_db() as conn:
        conn.execute("DELETE FROM users WHERE username = ?", (username,))
        conn.commit()


def save_users_to_secrets(users: dict):
    """
    Compatibility shim — persists all users to SQLite.
    Called wherever the old secrets-based save was used.
    """
    for uname, ud in users.items():
        save_user_to_db(uname, ud)
    # Keep session_state in sync
    st.session_state.users = load_users_from_db()


# Initialise DB on every cold start
init_db()


